21	const FIRST_INSURANCE_SURCHARGE = 0.1;
22	
23	// Rounds up in MHPCO's favor, guarding against floating-point drift
24	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
25	const roundUpInFavor = (amount: number): number =>
26	  Math.ceil(Number(amount.toFixed(6)));
