30	  for (const item of items) {
31	    basePremiumTotal += BASE_PREMIUMS[item.type] * (1 + FIRST_INSURANCE_SURCHARGE);
32	  }
33	  const exactPremium = basePremiumTotal + PROCESSING_FEE;
34	  return { premium: roundUpInFavor(exactPremium) };
35	};
