const itemPremium = (item: Item): number =>
  BASE_PREMIUMS[item.type] * (1 + FIRST_INSURANCE_SURCHARGE);

export const quote = (customer: Customer, items: Item[]): QuoteResult => {
  const basePremiumTotal = items.reduce(
    (total, item) => total + itemPremium(item),
    0,
  );
  const exactPremium = basePremiumTotal + PROCESSING_FEE;
  return { premium: roundUpInFavor(exactPremium) };
};
